-- transaction
BEGIN;
INSERT INTO orders (id, total) VALUES (1, 500);
INSERT INTO order_items (order_id, product_id) VALUES (1, 42);
COMMIT;

await db.transaction(async (trx) => {
  await trx('orders').insert({id: 1, total: 500});
  await trx('order_items').insert({order_id: 1, product_id: 42});
});

try {
